class Switch:
    def __init__(self, num_ports: int):
        self.num_ports = num_ports
        self.mac_table = {}
        self.log = []

    def process_frame(self, src_mac: str, dst_mac: str, ingress_port: int) -> str:
        src = src_mac.lower()
        dst = dst_mac.lower()
        self.mac_table[src] = ingress_port
        if dst == 'ff:ff:ff:ff:ff:ff':
            action = 'FLOOD'
        elif dst in self.mac_table:
            if self.mac_table[dst] == ingress_port:
                action = 'FILTER'
            else:
                action = f'FORWARD:{self.mac_table[dst]}'
        else:
            action = 'FLOOD'
        self.log.append(action)
        return action

    def get_mac_table(self) -> dict:
        return dict(self.mac_table)

    def clear_mac_table(self):
        self.mac_table.clear()
